let dadosRecebidosDaAPI;
if ($input.item && typeof $input.item.json !== 'undefined') {
    dadosRecebidosDaAPI = $input.item.json;
} else if ($items && $items.length > 0 && typeof $items[0].json !== 'undefined') {
    dadosRecebidosDaAPI = $items[0].json;
} else {
    console.error("Nenhum dado JSON de entrada encontrado ou formato inesperado.");
    return [{ json: { erro: "Dados de entrada não encontrados ou em formato incorreto." } }];
}

let objetoPrincipal;
if (Array.isArray(dadosRecebidosDaAPI) && dadosRecebidosDaAPI.length > 0) {
    objetoPrincipal = dadosRecebidosDaAPI[0];
} else if (typeof dadosRecebidosDaAPI === 'object' && dadosRecebidosDaAPI !== null && dadosRecebidosDaAPI.hasOwnProperty('itensTabelaPreco')) {
    objetoPrincipal = dadosRecebidosDaAPI;
} else {
    console.error("Estrutura do JSON da API não reconhecida ou chave 'itensTabelaPreco' não encontrada no objeto principal.");
    return [{ json: { erro: "Estrutura do JSON da API não reconhecida ou 'itensTabelaPreco' ausente." } }];
}

if (!objetoPrincipal || typeof objetoPrincipal.itensTabelaPreco === 'undefined' || !Array.isArray(objetoPrincipal.itensTabelaPreco)) {
    console.error("'itensTabelaPreco' não é um array válido ou não foi encontrado.");
    return [{ json: { erro: "'itensTabelaPreco' não encontrado ou não é um array." } }];
}

const listaDeProdutosOriginal = objetoPrincipal.itensTabelaPreco;

const listaDeProdutosFinal = listaDeProdutosOriginal.map(produto => {
    let precoTratado = null;
    if (produto.preco && typeof produto.preco === 'string') {
        const precoLimpo = produto.preco.replace(/\./g, '').replace(',', '.');
        const valorNumerico = parseFloat(precoLimpo);
        if (!isNaN(valorNumerico)) {
            precoTratado = valorNumerico;
        } else {
            console.warn(`Preço inválido "${produto.preco}" para produto ID: ${produto.idProduto || 'N/A'}`);
        }
    } else if (typeof produto.preco === 'number') {
        precoTratado = produto.preco;
    }

    return {
        descricaoProduto: produto.descricaoProduto || "Sem descrição",
        idProduto: produto.idProduto || null,
        nomeProduto: produto.nomeProduto || "Sem nome",
        preco: precoTratado,
        siglaUnidadeMedidaProduto: produto.siglaUnidadeMedidaProduto || "UN",
        ativo: objetoPrincipal.ativo, 
        idTabela: objetoPrincipal.id  
    };
});

return listaDeProdutosFinal;

// Pega todos os itens que vieram do Merge
const pedidosPagina = $input.all();

// Processa item por item
const pedidosTratados = pedidosPagina.map(item => {
  const json = item.json;

  // 1. Tratamento do valor monetário (transforma "1.000,00" em 1000.00)
  let valorTratado = 0;
  if (json.valorTotal) {
      valorTratado = Number(String(json.valorTotal).replace(/\./g,'').replace(',', '.'));
  }

  // 2. Tratamento de Data (transforma DD/MM/YYYY HH:mm:ss para formato ISO do banco)
  // Obs: O n8n geralmente lida bem com datas ISO, vamos tentar converter nativamente
  // Se der erro de data, avise que usamos a biblioteca DateTime
  let dataTratada = null;
  if (json.dataCriacao) {
     // Exemplo simples de conversão, ajustando se necessário
     const [data, hora] = json.dataCriacao.split(' ');
     const [dia, mes, ano] = data.split('/');
     dataTratada = `${ano}-${mes}-${dia}T${hora}`; // Formato ISO 8601
  }

  // 3. Lógica do Status (Resolve o seu problema principal)
  const obs = json.observacoesInternas;
  const temProblema = obs && obs.trim() !== "";

  // Se não tem problema, passamos string vazia ou NULL para limpar o banco
  const observacaoFinal = temProblema ? obs : null;

  // Definimos um status para você filtrar fácil no banco depois
  const statusPedido = temProblema ? "COM_PROBLEMA" : "RESOLVIDO";

  return {
    json: {
      codigo_pedido: json.codigoPedido,
      id_tipo_pedido: json.idTipoPedido,
      valor_total: valorTratado,
      observacoes_internas: observacaoFinal,
      data_criacao: dataTratada,
      itens_pedido: { data: json.itensPedido }, // Formato JSONB
      status_monitoramento: statusPedido, // Novo campo útil
      data_atualizacao: new Date().toISOString() // Para saber quando o robô passou
    }
  };
});

return pedidosTratados;

